   137→/**
   138→ * Default note values
   139→ */
   140→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   141→  const now = new Date();
   142→  return {
   143→    id: uuidv4(),
   144→    folderId: null,
   145→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   146→    content: '', // Empty Lexical state
   147→    contentText: '',
   148→    tags: [],
   149→    createdAt: now,
   150→    updatedAt: now,
   151→    isPinned: false,
   152→    isArchived: false,
   153→    ...overrides,
   154→  };
   155→};
   156→
   157→/**
   158→ * Sort notes based on sort config
   159→ */
   160→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   161→  const sorted = [...notes];
   162→
   163→  sorted.sort((a, b) => {
   164→    let comparison = 0;
   165→
   166→    switch (config.field) {
   167→      case 'title':
   168→        comparison = a.title.localeCompare(b.title);
   169→        break;
   170→      case 'createdAt':
   171→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   172→        break;
   173→      case 'updatedAt':
   174→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   175→        break;
   176→      case 'manual':
   177→        // Manual sort - preserve order (could add sortOrder field in future)
   178→        comparison = 0;
   179→        break;
   180→    }
   181→
   182→    return config.order === 'asc' ? comparison : -comparison;
   183→  });
   184→
   185→  // Always pin pinned notes to top
   186→  return sorted.sort((a, b) => {
   187→    if (a.isPinned && !b.isPinned) return -1;
   188→    if (!a.isPinned && b.isPinned) return 1;
   189→    return 0;
   190→  });
   191→};
   192→
   193→/**
   194→ * Filter notes based on filter type
   195→ */
   196→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   197→  switch (filter) {
   198→    case 'favorites':
   199→      return notes.filter((note) => note.isFavorite);
   200→    case 'pinned':
   201→      return notes.filter((note) => note.isPinned);
   202→    case 'archived':
   203→      return notes.filter((note) => note.isArchived);
   204→    case 'unarchived':
   205→      return notes.filter((note) => !note.isArchived);
   206→    case 'all':
   207→    default:
   208→      return notes;
   209→  }
   210→};
