   251→
   252→        // Only update timestamp if content/title/tags actually changed
   253→        // Skip timestamp update for UI-only changes (like folderId without content change)
   254→        const shouldUpdateTimestamp =
   255→          updates.content !== undefined ||
   256→          updates.title !== undefined ||
   257→          updates.tags !== undefined;
   258→
   259→        set((state) => ({
   260→          notes: {
   261→            ...state.notes,
   262→            [id]: {
   263→              ...note,
   264→              ...updates,
   265→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   266→            },
   267→          },
   268→        }));
   269→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   270→      },
   271→
   272→      deleteNote: (id) => {
   273→        // Save note for undo
   274→        const noteToDelete = get().notes[id];
   275→        if (!noteToDelete) {
   276→          log.warn('Note not found', { id });
   277→          return;
   278→        }
   279→
   280→        // Store the previous activeNoteId for undo
   281→        const wasActive = get().activeNoteId === id;
   282→
   283→        // Delete the note
   284→        set((state) => {
   285→          const { [id]: deleted, ...remainingNotes } = state.notes;
   286→          return {
   287→            notes: remainingNotes,
   288→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   289→          };
   290→        });
   291→
   292→        log.debug('Note deleted', { id });
   293→
   294→        // Delete associated images from IndexedDB (async, fire-and-forget)
   295→        import('../services/indexedDB').then(({ indexedDBService }) => {
   296→          indexedDBService.deleteNoteImages(id).catch((err) => {
   297→            log.error('Failed to delete note images', { id, error: err });
   298→          });
   299→        });
   300→
   301→        // Add undo action
   302→        useUndoStore.getState().addUndoAction(
   303→          `Note "${noteToDelete.title}" deleted`,
   304→          () => {
   305→            // Restore the note
   306→            set((state) => ({
   307→              notes: {
   308→                ...state.notes,
   309→                [id]: noteToDelete,
   310→              },
   311→              activeNoteId: wasActive ? id : state.activeNoteId,
   312→            }));
   313→            log.debug('Note restored (undo)', { id });
   314→          }
   315→        );
   316→      },
   317→
   318→      duplicateNote: (id) => {
   319→        const original = get().notes[id];
   320→        if (!original) {
