   201→      return { success: false, error: 'Invalid ICS file format' };
   202→    }
   203→
   204→    const events: CalendarEvent[] = [];
   205→    const debugLog: string[] = [];
   206→
   207→    // Split into individual events
   208→    const eventBlocks = icsData.split('BEGIN:VEVENT').slice(1);
   209→    debugLog.push(`Found ${eventBlocks.length} event blocks`);
   210→
   211→    eventBlocks.forEach((block, index) => {
   212→      const endIndex = block.indexOf('END:VEVENT');
   213→      if (endIndex === -1) return;
   214→
   215→      const eventContent = block.slice(0, endIndex);
   216→      // Properly unfold lines per ICS spec (RFC 5545)
   217→      const lines = unfoldICSLines(eventContent);
   218→
   219→      const event: Partial<CalendarEvent> = {
   220→        id: `imported-${Date.now()}-${index}`,
   221→      };
   222→
   223→      let startDate = '';
   224→      let endDate = '';
   225→      let startTime: string | undefined;
   226→      let endTime: string | undefined;
   227→      let isRecurrenceException = false;
   228→
   229→      lines.forEach(line => {
   230→        // Properties can have parameters like DTSTART;VALUE=DATE:20231225
   231→        // or DTSTART;TZID=America/New_York:20231225T090000
   232→        const colonIndex = line.indexOf(':');
   233→        if (colonIndex === -1) return;
   234→
   235→        const propertyPart = line.slice(0, colonIndex);
   236→        const valuePart = line.slice(colonIndex + 1);
   237→
   238→        // Extract the property name (before any semicolon parameters)
   239→        const propertyName = propertyPart.split(';')[0].toUpperCase();
   240→
   241→        if (propertyName === 'SUMMARY') {
   242→          event.title = valuePart.replace(/\\n/g, '\n').replace(/\\,/g, ',').replace(/\\\\/g, '\\');
   243→        } else if (propertyName === 'DESCRIPTION') {
   244→          event.description = valuePart.replace(/\\n/g, '\n').replace(/\\,/g, ',').replace(/\\\\/g, '\\');
   245→        } else if (propertyName === 'LOCATION') {
   246→          event.location = valuePart.replace(/\\,/g, ',');
   247→        } else if (propertyName === 'UID') {
   248→          // Use UID if available, sanitize for use as ID
   249→          event.id = valuePart.replace(/[^a-zA-Z0-9-_@.]/g, '_');
   250→        } else if (propertyName === 'DTSTART') {
   251→          const parsed = parseICSDateTime(valuePart);
   252→          startDate = parsed.date;
   253→          startTime = parsed.time;
   254→          if (index < 5) {
   255→            debugLog.push(`Event ${index}: DTSTART raw='${valuePart}' parsed date='${startDate}' time='${startTime}'`);
   256→          }
   257→        } else if (propertyName === 'DTEND') {
   258→          const parsed = parseICSDateTime(valuePart);
   259→          endDate = parsed.date;
   260→          endTime = parsed.time;
   261→        } else if (propertyName === 'RRULE') {
   262→          event.recurrence = parseRRule(`RRULE:${valuePart}`);
   263→          if (index < 5) {
   264→            debugLog.push(`Event ${index}: RRULE='${valuePart}' parsed=${JSON.stringify(event.recurrence)}`);
   265→          }
   266→        } else if (propertyName === 'RECURRENCE-ID') {
   267→          // This is an exception to a recurring event series
   268→          // Skip these as we'll generate instances from the master event's RRULE
   269→          isRecurrenceException = true;
   270→        }
   271→      });
   272→
   273→      // Skip recurrence exceptions (individual overrides of recurring events)
   274→      if (isRecurrenceException) {
   275→        debugLog.push(`Event ${index} skipped: recurrence exception`);
   276→        return;
   277→      }
   278→
   279→      // Only add events with at least a title and date
   280→      if (event.title && startDate) {
   281→        event.startTime = startTime;
   282→        event.endTime = endTime;
   283→        event.isAllDay = !startTime;
