   310→/**
   311→ * Download .ics file
   312→ */
   313→export const downloadICS = (icsData: string, filename: string = 'calendar.ics'): void => {
   314→  const blob = new Blob([icsData], { type: 'text/calendar;charset=utf-8' });
   315→  const url = URL.createObjectURL(blob);
   316→  const link = document.createElement('a');
   317→  link.href = url;
   318→  link.download = filename;
   319→  document.body.appendChild(link);
   320→  link.click();
   321→  document.body.removeChild(link);
   322→  URL.revokeObjectURL(url);
   323→};
   324→
   325→/**
   326→ * Read .ics file from file input
   327→ */
   328→export const readICSFile = (file: File): Promise<string> => {
   329→  return new Promise((resolve, reject) => {
   330→    const reader = new FileReader();
   331→    reader.onload = (e) => {
   332→      const content = e.target?.result;
   333→      if (typeof content === 'string') {
   334→        resolve(content);
   335→      } else {
   336→        reject(new Error('Failed to read file as text'));
   337→      }
   338→    };
   339→    reader.onerror = () => reject(new Error('Failed to read file'));
   340→    reader.readAsText(file);
   341→  });
   342→};
